#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/stat.h>
#include <dirent.h>
#include <time.h>
#include <errno.h>

#define MAX_PATH 4096
#define MAX_MSG  256
#define MAX_LINE 8192

typedef struct {
    char hash[41];
    char msg[MAX_MSG];
    time_t ts;
} Commit;

int dir_exists(const char* path) {
    struct stat st;
    return stat(path, &st) == 0 && S_ISDIR(st.st_mode);
}

int file_exists(const char* path) {
    struct stat st;
    return stat(path, &st) == 0 && S_ISREG(st.st_mode);
}

void sha1(const char* data, char out[41]) {
    // Dummy SHA1: first 40 chars of data
    snprintf(out, 41, "%s", data);
    out[40] = '\0';
}

void init_repo() {
    if (dir_exists(".minigit")) {
        fprintf(stderr, "Repository already exists\n");
        exit(1);
    }
    mkdir(".minigit", 0755);
    mkdir(".minigit/objects", 0755);
    mkdir(".minigit/refs", 0755);
    FILE* fp = fopen(".minigit/HEAD", "w");
    if (!fp) { perror("HEAD"); exit(1); }
    fprintf(fp, "ref: refs/heads/main\n");
    fclose(fp);
    fp = fopen(".minigit/index", "w");
    fclose(fp);
    printf("Initialized empty minigit repository\n");
}

void read_index(char*** paths, int* cnt) {
    *cnt = 0;
    *paths = NULL;
    FILE* fp = fopen(".minigit/index", "r");
    if (!fp) return;
    char line[MAX_PATH];
    while (fgets(line, sizeof(line), fp)) {
        line[strcspn(line, "\n")] = 0;
        *paths = realloc(*paths, (*cnt + 1) * sizeof(char*));
        (*paths)[*cnt] = strdup(line);
        (*cnt)++;
    }
    fclose(fp);
}

void write_index(char** paths, int cnt) {
    FILE* fp = fopen(".minigit/index", "w");
    if (!fp) { perror("index"); exit(1); }
    for (int i = 0; i < cnt; i++) {
        fprintf(fp, "%s\n", paths[i]);
    }
    fclose(fp);
}

void copy_file(const char* src, const char* dst) {
    char cmd[2 * MAX_PATH + 20];
    snprintf(cmd, sizeof(cmd), "cp \"%s\" \"%s\"", src, dst);
    system(cmd);
}

void add_file(const char* path) {
    if (!file_exists(path)) {
        fprintf(stderr, "file not found: %s\n", path);
        exit(1);
    }
    char** paths;
    int cnt;
    read_index(&paths, &cnt);
    // avoid duplicates
    int found = 0;
    for (int i = 0; i < cnt; i++) {
        if (strcmp(paths[i], path) == 0) { found = 1; break; }
    }
    if (!found) {
        paths = realloc(paths, (cnt + 1) * sizeof(char*));
        paths[cnt] = strdup(path);
        cnt++;
    }
    write_index(paths, cnt);
    for (int i = 0; i < cnt; i++) free(paths[i]);
    free(paths);
}

char* current_branch() {
    static char branch[256];
    FILE* fp = fopen(".minigit/HEAD", "r");
    if (!fp) { perror("HEAD"); exit(1); }
    char line[256];
    fgets(line, sizeof(line), fp);
    fclose(fp);
    // "ref: refs/heads/main"
    char* p = strchr(line, ' ');
    if (!p) { fprintf(stderr, "bad HEAD\n"); exit(1); }
    p++;
    char* nl = strchr(p, '\n');
    if (nl) *nl = 0;
    snprintf(branch, sizeof(branch), "%s", p);
    return branch;
}

char* branch_head_path() {
    static char path[MAX_PATH];
    snprintf(path, sizeof(path), ".minigit/%s", current_branch());
    return path;
}

char* last_commit_hash() {
    static char hash[41];
    hash[0] = 0;
    char* p = branch_head_path();
    FILE* fp = fopen(p, "r");
    if (fp) {
        fgets(hash, 41, fp);
        fclose(fp);
        char* nl = strchr(hash, '\n');
        if (nl) *nl = 0;
    }
    return hash;
}

void write_commit(const char* hash, const char* msg) {
    // write object
    char objpath[MAX_PATH];
    snprintf(objpath, sizeof(objpath), ".minigit/objects/%s", hash);
    FILE* fp = fopen(objpath, "w");
    if (!fp) { perror(objpath); exit(1); }
    // store parent
    char* parent = last_commit_hash();
    fprintf(fp, "parent %s\n", parent);
    fprintf(fp, "msg %s\n", msg);
    // store index
    char** paths;
    int cnt;
    read_index(&paths, &cnt);
    fprintf(fp, "index\n");
    for (int i = 0; i < cnt; i++) {
        fprintf(fp, "%s\n", paths[i]);
    }
    fprintf(fp, "endindex\n");
    // store blobs
    for (int i = 0; i < cnt; i++) {
        char blobname[45];
        snprintf(blobname, sizeof(blobname), "%s.%s", hash, paths[i]);
        char blobpath[MAX_PATH];
        snprintf(blobpath, sizeof(blobpath), ".minigit/objects/%s", blobname);
        copy_file(paths[i], blobpath);
        fprintf(fp, "blob %s %s\n", paths[i], blobname);
    }
    fclose(fp);
    // update branch
    char* branchpath = branch_head_path();
    fp = fopen(branchpath, "w");
    if (!fp) { perror(branchpath); exit(1); }
    fprintf(fp, "%s\n", hash);
    fclose(fp);
    for (int i = 0; i < cnt; i++) free(paths[i]);
    free(paths);
}

void commit_cmd(const char* msg) {
    char** paths;
    int cnt;
    read_index(&paths, &cnt);
    if (cnt == 0) {
        fprintf(stderr, "nothing to commit\n");
        exit(1);
    }
    // build content for hash
    char content[1024];
    snprintf(content, sizeof(content), "%s%ld", msg, time(NULL));
    char hash[41];
    sha1(content, hash);
    write_commit(hash, msg);
    printf("Committed %s\n", hash);
    for (int i = 0; i < cnt; i++) free(paths[i]);
    free(paths);
}

void log_cmd() {
    char* p = branch_head_path();
    FILE* fp = fopen(p, "r");
    if (!fp) {
        printf("No commits yet\n");
        return;
    }
    char hash[41];
    while (fgets(hash, sizeof(hash), fp)) {
        char* nl = strchr(hash, '\n');
        if (nl) *nl = 0;
        // read object
        char objpath[MAX_PATH];
        snprintf(objpath, sizeof(objpath), ".minigit/objects/%s", hash);
        FILE* obj = fopen(objpath, "r");
        if (!obj) { perror(objpath); exit(1); }
        char line[256];
        char msg[MAX_MSG] = "";
        while (fgets(line, sizeof(line), obj)) {
            if (strncmp(line, "msg ", 4) == 0) {
                strncpy(msg, line + 4, sizeof(msg) - 1);
                msg[strcspn(msg, "\n")] = 0;
                break;
            }
        }
        fclose(obj);
        printf("commit %s %s\n", hash, msg);
        // open previous commit
        fclose(fp);
        // read parent
        obj = fopen(objpath, "r");
        char parent[41] = "";
        while (fgets(line, sizeof(line), obj)) {
            if (strncmp(line, "parent ", 7) == 0) {
                strncpy(parent, line + 7, 40);
                parent[40] = 0;
                char* nl = strchr(parent, '\n');
                if (nl) *nl = 0;
                break;
            }
        }
        fclose(obj);
        if (strlen(parent) == 0) break;
        // continue with parent
        snprintf(objpath, sizeof(objpath), ".minigit/objects/%s", parent);
        fp = fopen(objpath, "r");
        if (!fp) break;
        // read hash inside
        while (fgets(line, sizeof(line), fp)) {
            if (strncmp(line, "commit ", 7) == 0) {
                strncpy(hash, line + 7, 40);
                hash[40] = 0;
                break;
            }
        }
        fclose(fp);
        fp = fopen(".minigit/objects/" parent, "r");
        if (!fp) break;
        // re-read hash from parent file
        FILE* tmp = fopen(".minigit/objects/" parent, "r");
        if (!tmp) break;
        while (fgets(line, sizeof(line), tmp)) {
            if (strncmp(line, "commit ", 7) == 0) {
                strncpy(hash, line + 7, 40);
                hash[40] = 0;
                break;
            }
        }
        fclose(tmp);
        // now reopen parent object file
        fclose(fp);
        fp = fopen(".minigit/objects/" parent, "r");
        if (!fp) break;
        // read hash again
        while (fgets(line, sizeof(line), fp)) {
            if (strncmp(line, "commit ", 7) == 0) {
                strncpy(hash, line + 7, 40);
                hash[40] = 0;
                break;
            }
        }
        // now we have parent hash in 'hash'
        snprintf(hash, sizeof(hash), "%s", parent);
        fclose(fp);
        fp = fopen(".minigit/objects/" hash, "r");
        if (!fp) break;
    }
    if (fp) fclose(fp);
}

void checkout_cmd(const char* hash) {
    // read commit object
    char objpath[MAX_PATH];
    snprintf(objpath, sizeof(objpath), ".minigit/objects/%s", hash);
    if (!file_exists(objpath)) {
        fprintf(stderr, "commit not found: %s\n", hash);
        exit(1);
    }
    FILE* fp = fopen(objpath, "r");
    if (!fp) { perror(objpath); exit(1); }
    char line[MAX_LINE];
    // clear index
    write_index(NULL, 0);
    char** paths = NULL;
    int cnt = 0;
    while (fgets(line, sizeof(line), fp)) {
        if (strncmp(line, "blob ", 5) == 0) {
            char path[MAX_PATH], blobname[MAX_PATH];
            sscanf(line + 5, "%s %s", path, blobname);
            char blobpath[MAX_PATH];
            snprintf(blobpath, sizeof(blobpath), ".minigit/objects/%s", blobname);
            copy_file(blobpath, path);
            // add to index
            paths = realloc(paths, (cnt + 1) * sizeof(char*));
            paths[cnt] = strdup(path);
            cnt++;
        }
    }
    fclose(fp);
    write_index(paths, cnt);
    for (int i = 0; i < cnt; i++) free(paths[i]);
    free(paths);
}

void reset_cmd(const char* mode, const char* hash) {
    // move branch pointer
    char* branchpath = branch_head_path();
    FILE* fp = fopen(branchpath, "w");
    if (!fp) { perror(branchpath); exit(1); }
    fprintf(fp, "%s\n", hash);
    fclose(fp);
    if (mode && strcmp(mode, "--hard") == 0) {
        checkout_cmd(hash);
    } else {
        // mixed: leave working tree, update index
        checkout_cmd(hash);
    }
}

int main(int argc, char* argv[]) {
    if (argc < 2) {
        fprintf(stderr, "usage: minigit <command>\n");
        return 1;
    }
    if (strcmp(argv[1], "init") == 0) {
        init_repo();
    } else if (strcmp(argv[1], "add") == 0) {
        if (argc < 3) {
            fprintf(stderr, "usage: minigit add <file>\n");
            return 1;
        }
        add_file(argv[2]);
    } else if (strcmp(argv[1], "commit") == 0) {
        if (argc < 4 || strcmp(argv[2], "-m") != 0) {
            fprintf(stderr, "usage: minigit commit -m <message>\n");
            return 1;
        }
        commit_cmd(argv[3]);
    } else if (strcmp(argv[1], "log") == 0) {
        log_cmd();
    } else if (strcmp(argv[1], "checkout") == 0) {
        if (argc < 3) {
            fprintf(stderr, "usage: minigit checkout <commit>\n");
            return 1;
        }
        checkout_cmd(argv[2]);
    } else if (strcmp(argv[1], "reset") == 0) {
        const char* mode = NULL;
        const char* hash;
        if (argc == 4) {
            hash = argv[3];
            if (strcmp(argv[2], "--hard") == 0) mode = "--hard";
            else { fprintf(stderr, "unknown option %s\n", argv[2]); return 1; }
        } else if (argc == 3) {
            hash = argv[2];
        } else {
            fprintf(stderr, "usage: minigit reset [--hard] <commit>\n");
            return 1;
        }
        reset_cmd(mode, hash);
    } else {
        fprintf(stderr, "unknown command: %s\n", argv[1]);
        return 1;
    }
    return 0;
}
